mapper.select:
SELECT EVIM.EV_ITEM_NUM ,EVIM.EV_ITEM_KIND_CD ,EVIM.EV_ITEM_TYPE_CD ,GETCOMCODE(EVIM.GATE_CD, CASE EVIM.EV_ITEM_KIND_CD WHEN 'E' THEN 'M114' ELSE 'M113' END ,EVIM.EV_ITEM_TYPE_CD, '0', #{ses.langCd}) AS EV_ITEM_TYPE_NM ,EVIM.EV_ITEM_METHOD_CD ,EVIM.SCALE_TYPE_CD ,EVIM.EV_ITEM_SUBJECT ,EVIM.EV_ITEM_CONTENTS ,(SELECT COUNT(GATE_CD) FROM STOCEVID WHERE GATE_CD = EVIM.GATE_CD AND BUYER_CD = EVIM.BUYER_CD AND EV_ITEM_NUM = EVIM.EV_ITEM_NUM AND DEL_FLAG ='0' ) AS SCALE_COUNT ,(EVIM.MOD_DATE, 'YYYY-MM-DD HH24:MI') AS MOD_DATE --,EVIM.MOD_USER_ID , GETUSERNAME(#{ses.gateCd}, EVIM.MOD_USER_ID,#{ses.langCd}) AS MOD_USER_NM ,GATE_CD ,QTY_ITEM_CD FROM STOCEVIM EVIM WHERE EVIM.GATE_CD = #{ses.gateCd} AND EVIM.BUYER_CD = #{ses.companyCd} AND EVIM.DEL_FLAG = '0' AND EVIM.CREATE_TYPE_CD = 'S' --AND EVIM.EV_ITEM_DIV_CD IN ('SITE', 'EXEC')
AND EVIM.EV_ITEM_KIND_CD = #{EV_ITEM_KIND_CD}
AND EVIM.EV_ITEM_TYPE_CD = #{EV_ITEM_TYPE_CD}
AND EVIM.EV_ITEM_METHOD_CD = #{EV_ITEM_METHOD_CD}
AND UPPER(EVIM.EV_ITEM_SUBJECT) LIKE UPPER('%' #{EV_ITEM_SUBJECT} '%')
AND UPPER(EVIM.EV_ITEM_CONTENTS) LIKE UPPER('%' #{EV_ITEM_CONTENTS} '%')
ORDER BY EVIM.EV_ITEM_KIND_CD, EVIM.EV_ITEM_TYPE_CD, EVIM.EV_ITEM_METHOD_CD, EVIM.SCALE_TYPE_CD

