mapper.update:
        UPDATE STOCEVIM
        SET
			 MOD_DATE = SYSDATE
            ,MOD_USER_ID = #{ses.userId}
	        ,EV_ITEM_DIV_CD    = #{EV_ITEM_KIND_CD_RT}
			,SI_RA_TYPE          = NULL
			,AXIS_CD           = NULL
			,EV_ITEM_TYPE_CD   = #{EV_ITEM_TYPE_CD_RT}
			,EV_ITEM_SUBJECT     = #{EV_ITEM_SUBJECT_RT}
			,EV_ITEM_CONTENTS    = #{EV_ITEM_CONTENTS_RT}
			,EV_ITEM_KIND_CD   = #{EV_ITEM_KIND_CD_RT}
			,EV_ITEM_METHOD_CD = #{EV_ITEM_METHOD_CD_RT}
			,SCALE_TYPE_CD     = #{SCALE_TYPE_CD_RT}
			,QTY_ITEM_CD = #{QTY_ITEM_CD}
        WHERE GATE_CD = #{ses.gateCd}
          AND BUYER_CD = #{ses.companyCd}
          AND EV_ITEM_NUM = #{EV_ITEM_NUM}

        UPDATE STOCEVID
        SET  EV_ID_ORDER = #{EV_ID_ORDER}
			,EV_ID_CONTENTS = #{EV_ID_CONTENTS}
			,EV_ID_SCORE = #{EV_ID_SCORE}
			,PASS_FAIL_CD = #{PASS_FAIL_CD}
			,EV_ID_METHOD = #{EV_ID_METHOD}
			,FROM_VALUE = #{FROM_VALUE}
			,FROM_CONDITION_CD = #{FROM_CONDITION_CD}
			,TO_VALUE = #{TO_VALUE}
			,TO_CONDITION_CD = #{TO_CONDITION_CD}

            , MOD_DATE = SYSDATE
            , MOD_USER_ID = #{ses.userId}
        WHERE GATE_CD = #{ses.gateCd}
          AND BUYER_CD = #{ses.companyCd}
          AND EV_ITEM_NUM = #{EV_ITEM_NUM}
          AND EV_ID_SQ = #{EV_ID_SQ}

UPDATE STOCEVIM
SET    DEL_FLAG = '1'
     , MOD_DATE = SYSDATE
     , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD = #{ses.gateCd}
  AND BUYER_CD = #{ses.companyCd}
  AND EV_ITEM_NUM = #{EV_ITEM_NUM}

